import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return 5 G processing fee for an empty item list");
    it.todo("should return base premium plus fee for a single sword");
    it.todo("should return base premium plus fee for a single amulet");
    it.todo("should return base premium plus fee for a single staff");
    it.todo("should return base premium plus fee for a single potion");
    it.todo("should return base premium plus fee for a single component (rune)");
    it.todo("should return block premium for exactly 3 alike components");
    it.todo("should not apply block for 4 alike components");
    it.todo("should apply block per type for 3 runes and 3 moonstones");
    it.todo("should add cursed surcharge (50%) to cursed item base premium");
    it.todo("should add high-enchantment surcharge (30%) for enchantment >= 5");
    it.todo("should apply both cursed and high-enchantment surcharges together");
    it.todo("should apply loyalty discount (20%) for customer with >= 2 years");
    it.todo("should apply first-insurance surcharge (10%) to each item in a quote");
    it.todo("should apply follow-up discount (15%) for second and later quotes");
    it.todo("should combine multiple modifiers correctly (integration)");
  });

  describe("claim", () => {
    it.todo("should return full damage minus 100 G deductible for standard item");
    it.todo("should return 50% of damage minus deductible for high enchantment (>= 8) item");
    it.todo("should return full damage minus deductible for dragon material item");
    it.todo("should use 50% rule when both high enchantment and dragon material apply");
    it.todo("should cap payout at remaining policy cap");
    it.todo("should track remaining cap across multiple claims");
    it.todo("should apply deductible per damaged item in same incident");
  });
});

