    it.todo("should return full damage minus 100 G deductible for standard item");
    it.todo("should return 50% of damage minus deductible for high enchantment (>= 8) item");
    it.todo("should return full damage minus deductible for dragon material item");
    it.todo("should use 50% rule when both high enchantment and dragon material apply");
    it.todo("should cap payout at remaining policy cap");
    it.todo("should track remaining cap across multiple claims");
    it.todo("should apply deductible per damaged item in same incident");
  });
});

