export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Customer = {
  yearsWithMHPCO: number;
  contractCount: number;
};

export type QuoteInput = {
  items: Item[];
  customer: Customer;
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export const quote = ({ items }: QuoteInput): number => {
  const countByType: Record<string, number> = {};
  for (const item of items) {
    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
  }
  const policyBase = Object.entries(countByType).reduce((sum, [type, count]) => {
    return sum + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type]);
  }, 0);
  const cursedSurcharge = items.reduce((sum, item) => {
    return sum + (item.cursed ? CURSED_SURCHARGE_RATE * BASE_PREMIUMS[item.type] : 0);
  }, 0);
  const enchantSurcharge = items.reduce((sum, item) => {
    return sum + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE_RATE * BASE_PREMIUMS[item.type] : 0);
  }, 0);
  return Math.ceil(policyBase + cursedSurcharge + enchantSurcharge + policyBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
};

export type Damage = {
  itemType: string;
  amount: number;
};

