export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Customer = {
  yearsWithMHPCO: number;
  contractCount: number;
};

export type QuoteInput = {
  items: Item[];
  customer: Customer;
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

export const quote = ({ items, customer }: QuoteInput): number => {
  const countByType: Record<string, number> = {};
  for (const item of items) {
    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
  }
  const policyBase = Object.entries(countByType).reduce((sum, [type, count]) => {
    return sum + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type]);
  }, 0);
  const itemSurcharges = items.reduce((sum, item) => {
    const base = BASE_PREMIUMS[item.type];
    const cursed = item.cursed ? CURSED_SURCHARGE_RATE * base : 0;
    const highEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base : 0;
    return sum + cursed + highEnchantment;
  }, 0);
  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT_RATE * policyBase : 0;
  return Math.ceil(policyBase + itemSurcharges - loyaltyDiscount + policyBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type Policy = {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
};

export type ClaimInput = {
  policy: Policy;
  incident: Incident;
};

export type ClaimResult = {
  payout: number;
  remainingCap: number;
};

export const claim = (_input: ClaimInput): ClaimResult => {
  return undefined as unknown as ClaimResult;
};

